import type {SpecificationProject} from "./data-layer-specification-project.js";

export interface EntityPurposeGuidance{purpose:string;example:string;prerequisites:string[];usedBy:string;distinguishesFrom:string}
const entityGuidance:Record<string,EntityPurposeGuidance>={
  Profile:{purpose:"A reusable set of requirements that describes what data must contain.",example:"Sitewide requirements can combine with Retail or Trade checkout requirements.",prerequisites:["Name the business requirement"],usedBy:"Used by Pages, Events, Flow steps, and Schemas.",distinguishesFrom:"Schema"},
  "Applicability Set":{purpose:"A named, reusable condition that decides when routing applies.",example:"Retail purchase context separates Retail from Trade on the shared Purchase event.",prerequisites:["Create the referenced Page or Event"],usedBy:"Used by Assignments and Flow routing.",distinguishesFrom:"Assignment"},
  Page:{purpose:"A shared named page context observed on the site.",example:"Checkout confirmation is shared by the Retail and Trade funnels.",prerequisites:["Describe its host or path"],usedBy:"Used by Flow steps, Fixtures, and applicability tests.",distinguishesFrom:"Flow step"},
  Event:{purpose:"A shared named data-layer occurrence that can be observed and validated.",example:"Purchase is shared by Retail and Trade while routing supplies the funnel context.",prerequisites:["Name the emitted event and observation source"],usedBy:"Used by Assignments, Flow steps, Fixtures, and Live.",distinguishesFrom:"Page"},
  Flow:{purpose:"An ordered journey with occurrence bounds, branches, joins, and transitions.",example:"Retail checkout permits an optional Upsell while Trade checkout follows its own steps.",prerequisites:["Create the shared Pages and Events used by its steps"],usedBy:"Used by Applicability, Assignments, Fixtures, Coverage, and Live.",distinguishesFrom:"Page"},
  Assignment:{purpose:"A named routing decision that connects an Event and Applicability Set to one project Schema.",example:"Retail Purchase and Trade Purchase select distinct schemas for the shared Purchase event.",prerequisites:["Create an Event, Applicability Set, and Schema"],usedBy:"Used by compilation, Fixtures, Coverage, Preflight, and Live.",distinguishesFrom:"Applicability Set"},
  Schema:{purpose:"A project-owned compiled contract composed from ordered Profiles and local overrides.",example:"Retail confirmation combines Sitewide and Retail Profiles while Trade uses Sitewide and Trade.",prerequisites:["Create at least one Profile"],usedBy:"Used by Assignments, Fixtures, Coverage, Release, and Live.",distinguishesFrom:"Profile"},
  Fixture:{purpose:"A repeatable observation and assertion that proves production evaluation.",example:"A Retail Purchase fixture proves the Retail winner and rejects the Trade route.",prerequisites:["Compile an Event, routing, and requirements"],usedBy:"Used by Coverage, Preflight, and Release review.",distinguishesFrom:"Live observation"},
  Draft:{purpose:"The mutable project revision used by authoring Preview.",example:"A Retail currency edit remains in Draft until the next release.",prerequisites:["Create or restore a project"],usedBy:"Used by Preview, Fixtures, Coverage, and Preflight.",distinguishesFrom:"Published release"},
};
export function entityPurposeGuidance(entity:string):EntityPurposeGuidance{return structuredClone(entityGuidance[entity]??{purpose:"A named part of the executable Specification Project.",example:"Retail and Trade share canonical project entities.",prerequisites:["Create a project"],usedBy:"Used by the compiled project graph.",distinguishesFrom:"another project entity"});}

export function projectAuthoringGuidance(project:SpecificationProject):{tasks:{label:string;complete:boolean}[];map:{name:string;complete:boolean;blocker?:string}[];continue:{label:string;reason:string;unlocks:string}}{
  const shared=project.collections.pages.length>0&&project.collections.events.length>0,requirements=project.collections.profiles.some(({requirements})=>requirements.length>0),flows=project.collections.flows.length>0,routing=project.collections.assignments.length>0,proof=project.collections.fixtures.length>0,released=Boolean(project.currentRelease);
  return{
    tasks:[{label:"Create a shared Purchase event",complete:project.collections.events.some(({name})=>name.toLowerCase()==="purchase")},{label:"Add a funnel",complete:flows},{label:"Add flow-specific requirements",complete:requirements},{label:"Prove checkout confirmation",complete:proof}],
    map:[{name:"Foundation",complete:true},{name:"Shared entities",complete:shared,...(!shared?{blocker:"Create a Page and Event"}:{})},{name:"Requirements",complete:requirements,...(!requirements?{blocker:"Add a Profile requirement"}:{})},{name:"Flows",complete:flows,...(!flows?{blocker:"Add a Flow"}:{})},{name:"Routing",complete:routing,...(!routing?{blocker:"Add an Assignment"}:{})},{name:"Proof",complete:proof,...(!proof?{blocker:"Run an assertion-bearing Fixture"}:{})},{name:"Release",complete:released,...(!released?{blocker:"Pass Preflight and publish"}:{})}],
    continue:!shared?{label:"Continue with shared entities",reason:"Pages and Events give the specification observable names.",unlocks:"Requirements and Flow authoring"}:!requirements?{label:"Continue with requirements",reason:"Profiles define the data contract.",unlocks:"Schema compilation and routing"}:!flows?{label:"Continue with Flows",reason:"Flows describe the journeys that select context.",unlocks:"Routing and Fixtures"}:!routing?{label:"Continue with routing",reason:"Assignments connect observations to effective schemas.",unlocks:"Fixtures and Coverage"}:!proof?{label:"Continue with proof",reason:"Fixtures prove the compiled behavior.",unlocks:"Coverage and Release"}:{label:"Continue to release",reason:"Preflight confirms one executable truth.",unlocks:"Published-plan Live"},
  };
}

export function projectImpactPreview(action:string,affectedEntities:string[]):{affectedEntities:string[];scope:string;runtimeConsequence:string;staleEvidence:string[]}{return{affectedEntities:[...affectedEntities],scope:action==="publish a release"?"Published release":"Draft only until publication",runtimeConsequence:action==="publish a release"?"Live switches atomically to the new immutable plan.":"Preview recompiles; Live remains on the published release.",staleEvidence:["Fixtures","Coverage","Preflight","Release review"]};}

const repairs:Record<string,{reason:string;action:string;field:string}>={
  "zero observations":{reason:"This Fixture contains no observations or assertions, so it cannot prove behavior.",action:"Open the named Fixture observations field",field:"Ordered observations"},
  "zero effective cells":{reason:"Coverage has no effective requirement cells because routing and compiled requirements do not intersect.",action:"Open the named Assignment applicability field",field:"Applicability Set"},
  "compiler failure":{reason:"Compilation stopped at an unresolved or invalid project field.",action:"Open the exact compiler diagnostic field",field:"Compiler diagnostic"},
  "unresolved ambiguity":{reason:"Two highest-priority Assignments can win the same observation.",action:"Open the named Applicability Set condition",field:"Nested condition"},
  "no permitted target":{reason:"Live cannot observe a page until access to its origin is granted.",action:"Choose a target and request access",field:"Observation target"},
};
export function assuranceRepairGuidance(state:string):{reason:string;action:string;field:string}{return structuredClone(repairs[state]??{reason:"This assurance stage is not ready.",action:"Open the first named blocker",field:"Blocking field"});}
